# Audit report: users with significant roles in BOTH systems
# High-privilege in both = maximum blast radius
Connect-MgGraph -Scopes 'RoleManagement.Read.Directory','User.Read.All'

# Step 1: get all Entra Global Administrators
$gaRoleId = (Get-MgRoleManagementDirectoryRoleDefinition -Filter "displayName eq 'Global Administrator'").Id
$gaAssignments = Get-MgRoleManagementDirectoryRoleAssignment -Filter "roleDefinitionId eq '$gaRoleId'" -ExpandProperty Principal
$gaObjectIds = $gaAssignments.PrincipalId

# Step 2: check which of them also have Owner in Azure RBAC
$owners = Get-AzRoleAssignment | Where-Object { $_.RoleDefinitionName -eq 'Owner' }

$crossPrivileged = $owners | Where-Object { $gaObjectIds -contains $_.ObjectId }
if ($crossPrivileged) {
    Write-Warning 'Users with both Global Administrator and Azure Owner — review immediately:'
    $crossPrivileged | Select-Object DisplayName, SignInName, Scope
} else {
    Write-Host 'No users hold both Global Administrator and Azure Owner.' -ForegroundColor Green
}

# Terraform: assign an Entra role using the AzureAD / AzureRM providers
# Use azuread provider for Entra roles, azurerm provider for Azure RBAC

# --- Entra role assignment (azuread provider) ---
data "azuread_client_config" "current" {}

data "azuread_directory_role" "user_admin" {
  display_name = "User Administrator"
}

resource "azuread_directory_role_assignment" "example" {
  role_id             = data.azuread_directory_role.user_admin.template_id
  principal_object_id = azuread_user.example.object_id
}

# --- Azure RBAC assignment (azurerm provider) ---
resource "azurerm_role_assignment" "example" {
  scope                = data.azurerm_subscription.current.id
  role_definition_name = "Reader"
  principal_id         = azuread_user.example.object_id
}

# The same object_id is used in both assignments — the user is the same,
# but the two assignments live in completely different systems.
# Destroying the azurerm_role_assignment does NOT affect azuread_directory_role_assignment.
